-- Ajouter siteVersage dans chantiers (si pas déjà présent)
ALTER TABLE chantiers ADD COLUMN IF NOT EXISTS "siteVersage" VARCHAR(255);

-- Ajouter bonCommandeSigne dans chantiers
ALTER TABLE chantiers ADD COLUMN IF NOT EXISTS "bonCommandeSigne" BOOLEAN DEFAULT FALSE;

-- Ajouter planningVersages dans chantiers
ALTER TABLE chantiers ADD COLUMN IF NOT EXISTS "planningVersages" TEXT;

-- Ajouter mailConditionsEnvoye dans transporteurs (si la table existe)
ALTER TABLE transporteurs ADD COLUMN IF NOT EXISTS "mailConditionsEnvoye" BOOLEAN DEFAULT FALSE NOT NULL;

-- Vérifier les colonnes ajoutées
SELECT column_name, data_type FROM information_schema.columns 
WHERE table_name IN ('chantiers', 'transporteurs') 
AND column_name IN ('siteVersage', 'bonCommandeSigne', 'planningVersages', 'mailConditionsEnvoye')
ORDER BY table_name, column_name;

